        var result = new ReconciliationResult();

        // ── 1. 파일 로드 ─────────────────────────────────────────────────
        JsonObject workstate;
        try
        {
            workstate = JsonNode.Parse(File.ReadAllText(opts.WorkstatePath)) as JsonObject
                ?? throw new InvalidOperationException("WORKSTATE is not a JSON object");
        }
        catch (Exception ex)
        {
            result.HarnessErrors.Add(H("workstate", "workstate-malformed", ex.Message));
            return result;
        }

        // ── 2. appliedTransitions 파싱 ───────────────────────────────────
        var stateIds = new List<string>();
        if (workstate["appliedTransitions"] is not JsonArray transitions)
        {
            result.HarnessErrors.Add(H("workstate.appliedTransitions", "workstate-malformed",
                "appliedTransitions is missing or not an array"));
            return result;
        }

        foreach (var node in transitions)
        {
            if (node is not JsonObject elem)
            {
                result.HarnessErrors.Add(H("workstate.appliedTransitions", "workstate-malformed",
                    "appliedTransitions element is not an object"));
                return result;
            }

            var id = elem["id"]?.GetValue<string>() ?? "";
            if (string.IsNullOrWhiteSpace(id))
            {
                result.HarnessErrors.Add(H("workstate.appliedTransitions", "workstate-malformed",
                    "appliedTransitions element has missing or empty id"));
                return result;
            }

            var appliedAt = elem["appliedAt"]?.GetValue<string>() ?? "";
            if (!IsValidUtcRfc3339(appliedAt))
            {
                result.HarnessErrors.Add(H($"workstate.appliedTransitions[{id}].appliedAt",
                    "workstate-malformed",
                    $"appliedAt is missing or not a valid UTC RFC3339 timestamp: '{appliedAt}'"));
                return result;
            }

            stateIds.Add(id);
        }

        // ── 3. applier-log.jsonl 파싱 ────────────────────────────────────
        var allLogEntries = new List<LogEntry>();
        if (!File.Exists(opts.ApplierLogPath))
        {
            result.HarnessErrors.Add(H("applier-log", "applier-log-malformed",
                $"applier-log not found: {opts.ApplierLogPath}"));
            return result;
        }

        foreach (var line in File.ReadLines(opts.ApplierLogPath))
        {
            var trimmed = line.Trim();
            if (string.IsNullOrEmpty(trimmed)) continue;

            JsonObject row;
            try
            {
                row = JsonNode.Parse(trimmed) as JsonObject
                    ?? throw new InvalidOperationException("log line is not a JSON object");
            }
            catch (Exception ex)
            {
                result.HarnessErrors.Add(H("applier-log", "applier-log-malformed",
                    $"log line is not valid JSON: {ex.Message}"));
                return result;
            }

            var tid = row["transitionId"]?.GetValue<string>() ?? "";
            if (string.IsNullOrWhiteSpace(tid))
            {
                result.HarnessErrors.Add(H("applier-log.transitionId", "applier-log-malformed",
                    "transitionId is missing or empty"));
                return result;
            }

            var res = row["result"];
            if (res is null || res.GetValueKind() != JsonValueKind.String)
            {
                result.HarnessErrors.Add(H($"applier-log[{tid}].result", "applier-log-malformed",
                    "result is missing or not a string"));
                return result;
            }

            int exitCode;
            try { exitCode = row["exitCode"]?.GetValue<int>() ?? throw new InvalidOperationException("missing"); }
            catch
            {
                result.HarnessErrors.Add(H($"applier-log[{tid}].exitCode", "applier-log-malformed",
                    "exitCode is missing or not an integer"));
                return result;
            }

            var at = row["at"]?.GetValue<string>() ?? "";
            if (!IsValidUtcRfc3339(at))
            {
                result.HarnessErrors.Add(H($"applier-log[{tid}].at", "applier-log-malformed",
                    $"at is missing or not a valid UTC RFC3339 timestamp: '{at}'"));
                return result;
            }

            // schemaVersion 판별
            int schemaVersion = 1;
            if (row["schemaVersion"] is { } sv && int.TryParse(sv.ToString(), out var parsedSv))
                schemaVersion = parsedSv;

            string? contractHash = null;
            if (schemaVersion >= 2)
            {
                var err = ValidateV2Fields(row, tid);
                if (err != null)
                {
                    result.HarnessErrors.Add(H($"applier-log[{tid}]", "applier-log-malformed", err));
                    return result;
                }
                contractHash = row["transitionContractSha256"]?.GetValue<string>();
            }

            allLogEntries.Add(new LogEntry(tid, res.GetValue<string>(), exitCode, at, schemaVersion, contractHash));
        }

        // ── 4. 집합 구성 ─────────────────────────────────────────────────
        var stateIdSet = new HashSet<string>(stateIds, StringComparer.Ordinal);
        var allLogIdSet = new HashSet<string>(
            allLogEntries.Select(e => e.TransitionId), StringComparer.Ordinal);

        var successfulEntries = allLogEntries
            .Where(e => string.Equals(e.Result, "ok", StringComparison.OrdinalIgnoreCase) && e.ExitCode == 0)
            .ToList();

        var successfulLogIdSet = new HashSet<string>(
            successfulEntries.Select(e => e.TransitionId), StringComparer.Ordinal);

        // 중복 id 분석
        var successCounts = successfulEntries
            .GroupBy(e => e.TransitionId, StringComparer.Ordinal)
            .ToDictionary(g => g.Key, g => g.ToList(), StringComparer.Ordinal);

        // 스키마 버전 분포
        var schemaVersions = new Dictionary<string, int>(StringComparer.Ordinal);
        foreach (var e in allLogEntries)
        {
            var key = $"v{e.SchemaVersion}";
            schemaVersions[key] = schemaVersions.GetValueOrDefault(key) + 1;
        }

        // ── 5. 중복 in-state 검사 ────────────────────────────────────────
        var seenStateIds = new HashSet<string>(StringComparer.Ordinal);
        foreach (var id in stateIds)
        {
            if (!seenStateIds.Add(id))
                result.Failures.Add(F(id, "duplicate-in-state",
                    $"transition id '{id}' appears more than once in appliedTransitions"));
        }

        // ── 6. 중복 성공 log 검사 ───────────────────────────────────────
        int duplicateSuccessLogCount = 0;
        foreach (var (id, entries) in successCounts.Where(kv => kv.Value.Count > 1))
        {
            duplicateSuccessLogCount++;
            var hasContract = entries.All(e => !string.IsNullOrEmpty(e.TransitionContractSha256));
            if (hasContract)
            {
                var distinct = entries.Select(e => e.TransitionContractSha256!).Distinct(StringComparer.OrdinalIgnoreCase).ToList();
                if (distinct.Count > 1)
                    result.Failures.Add(F(id, "duplicate-success-log-conflict",
                        $"transition id '{id}' has {entries.Count} success log entries with differing transitionContractSha256"));
                else
                    result.Warnings.Add(W(id, "duplicate-success-in-log",
                        $"transition id '{id}' appears {entries.Count} times in log (all same contract — append-only replay)"));
            }
            else
            {
                // v1 항목: contract hash 없음 — 중복 경고만 (06C-1이 legacy-idempotency-unverifiable 처리)
                result.Warnings.Add(W(id, "duplicate-success-in-log",
                    $"transition id '{id}' appears {entries.Count} times in log (v1 entries, contract binding unverifiable)"));
            }
        }

        // ── 7. 핵심 규칙 1: successfulLogIdSet ⊆ stateIdSet ─────────────
        // log에 성공 항목이 있는데 state에 없으면 사고 탐지
        foreach (var id in successfulLogIdSet)
        {
            if (!stateIdSet.Contains(id))
                result.Failures.Add(F(id, "log-transition-missing-from-state",
                    $"transition id '{id}' is in successful log but missing from appliedTransitions (possible mid-incident state)"));
        }

        // ── 8. 규칙 2: stateIdSet ⊆ allLogIdSet ────────────────────────
        // state의 모든 id는 log에 어떤 형태로든 기록이 있어야 한다.
        // PendingTransitionId: state에 1회, log에 없음, 정확히 1회 면제.
        var pendingExemptionApplied = false;
        foreach (var id in stateIdSet)
        {
            if (!allLogIdSet.Contains(id))
            {
                if (!string.IsNullOrEmpty(opts.PendingTransitionId)
                    && string.Equals(id, opts.PendingTransitionId, StringComparison.Ordinal)
                    && stateIds.Count(s => string.Equals(s, id, StringComparison.Ordinal)) == 1)
                {
                    pendingExemptionApplied = true;
                }
                else
                {
                    result.Failures.Add(F(id, "state-transition-not-logged",
                        $"transition id '{id}' is in appliedTransitions but has no log entry"));
                }
            }
        }

        // PendingTransitionId가 지정됐으나 state에 없거나 이미 log에 있으면 면제 미적용
        if (!string.IsNullOrEmpty(opts.PendingTransitionId) && !pendingExemptionApplied)
        {
            var pid = opts.PendingTransitionId;
            var inState = stateIds.Count(s => string.Equals(s, pid, StringComparison.Ordinal));
            var inLog = allLogIdSet.Contains(pid);
            if (inState != 1 || inLog)
            {
                // 면제 조건 불충족 — 이미 일반 규칙이 처리하므로 추가 failure 없음
            }
        }

        // ── 9. lookupSuccess 구성 (06C-1용) ─────────────────────────────
        foreach (var id in successfulLogIdSet)
        {
            var entries = successCounts.GetValueOrDefault(id) ?? [];
            var best = entries.FirstOrDefault();
            if (best is not null)
            {
                result.SuccessLookup[id] = new LogLookupResult(
                    true, best.SchemaVersion, best.TransitionContractSha256);
            }
        }

        // ── 10. 지표 기록 ────────────────────────────────────────────────
        var allFailuresEmpty = result.Failures.Count == 0 && result.HarnessErrors.Count == 0;
        result.Metrics = new ReconciliationMetrics(
            AppliedTransitionCount: stateIds.Count,
            SuccessfulLogEntryCount: successfulEntries.Count,
            SuccessfulLogIdCount: successfulLogIdSet.Count,
            DuplicateSuccessLogCount: duplicateSuccessLogCount,
            LogSchemaVersions: schemaVersions,
            PendingExemptionApplied: pendingExemptionApplied,
            Reconciliation: allFailuresEmpty ? "PASS" : "FAIL"
        );

        return result;
    }

    // v2 log 항목의 필수 필드를 검증한다. 오류 메시지를 반환하고 정상이면 null.
    private static string? ValidateV2Fields(JsonObject row, string tid)
    {
        var kind = row["transitionKind"]?.GetValue<string>() ?? "";
        if (!AllowedTransitionKinds.Contains(kind))
            return $"transitionKind is missing or invalid (got '{kind}')";

        foreach (var field in new[] { "requestSha256", "preStateSha256", "postStateSha256", "transitionContractSha256" })
        {
            var val = row[field]?.GetValue<string>() ?? "";
            if (!Is64Hex(val))
                return $"{field} is missing or not a 64-character hex string";
        }

        var effectiveAt = row["effectiveAt"]?.GetValue<string>() ?? "";
        if (!IsValidUtcRfc3339(effectiveAt))
            return $"effectiveAt is missing or not a valid UTC RFC3339 timestamp: '{effectiveAt}'";

        return null;
    }

    // 64자 16진수 문자열인지 확인한다.
    private static bool Is64Hex(string? s)
        => s is { Length: 64 } && s.All(c => (c >= '0' && c <= '9') || (c >= 'a' && c <= 'f') || (c >= 'A' && c <= 'F'));

    // UTC RFC3339 타임스탬프 형식인지 확인한다.
    private static bool IsValidUtcRfc3339(string? s)
    {
        if (string.IsNullOrWhiteSpace(s)) return false;
        return DateTimeOffset.TryParse(s,
            System.Globalization.CultureInfo.InvariantCulture,
            System.Globalization.DateTimeStyles.RoundtripKind, out _);
    }

    // 실패 항목을 만든다.
    private static ReconciliationEntry F(string s, string c, string m) => new(s, c, m);
    // 경고 항목을 만든다.
    private static ReconciliationEntry W(string s, string c, string m) => new(s, c, m);
    // 하네스 오류 항목을 만든다.
    private static ReconciliationEntry H(string s, string c, string m) => new(s, c, m);
}

